import numpy as np

def construct_packing():
    n = 26
    row_counts = [5, 4, 5, 4, 5, 3]
    r_height = 1.0 / (2 + 5 * np.sqrt(3))
    r = r_height * 0.99999
    dy = r * np.sqrt(3)
    centers = []
    y = r
    for c in row_counts:
        if c == 5:
